  report_emergency: { ko:"이미 피해를 당하셨나요? 지금 당장 신고하세요.", en:"Already a victim? Report immediately.", ja:"すでに被害を受けましたか？今すぐ通報してください。", zh:"已经受害了吗？立即举报。", vi:"Đã là nạn nhân? Hãy báo cáo ngay.", es:"¿Ya eres víctima? Denuncia de inmediato.", de:"Bereits Opfer? Sofort melden.", fr:"Déjà victime? Signalez immédiatement.", hi:"क्या आप पहले से पीड़ित हैं? अभी रिपोर्ट करें।", pt:"Já é vítima? Denuncie imediatamente.", th:"เป็นเหยื่ออยู่แล้ว? แจ้งทันที", uz:"Allaqachon jabrlanuvchimisiz? Darhol xabar bering", tl:"Biktima na? Mag-ulat agad", mn:"Хохирогч болсон уу? Даруй мэдүүлнэ үү", ru:"Уже жертва? Немедленно сообщите", id:"Sudah menjadi korban? Segera laporkan" },
  report_faster:    { ko:"신고가 빠를수록 계좌 지급정지로 피해금 환급 가능성이 높아집니다.", en:"The faster you report, the higher the chance of recovering your money.", ja:"早く通報するほど、口座凍結により被害金の回収可能性が高まります。", zh:"举报越快，通过账户冻结追回损失的可能性越高。", vi:"Báo cáo càng nhanh, cơ hội thu hồi tiền càng cao.", es:"Cuanto más rápido denuncies, mayor será la posibilidad de recuperar tu dinero.", de:"Je schneller Sie melden, desto höher die Chance auf Rückerstattung.", fr:"Plus vite vous signalez, plus les chances de récupérer votre argent sont élevées.", hi:"जितनी जल्दी रिपोर्ट करेंगे, पैसे वापस मिलने की संभावना उतनी अधिक।", pt:"Quanto mais rápido denunciar, maior a chance de recuperar seu dinheiro.", th:"ยิ่งแจ้งเร็ว โอกาสได้เงินคืนยิ่งสูง", uz:"Tezroq xabar bersangiz, pulni qaytarish imkoniyati oshadi", tl:"Mas mabilis ang pag-uulat, mas mataas ang tsansa ng pagbawi ng pera", mn:"Хурдан мэдүүлэх тусам мөнгө буцааж авах боломж өндөр", ru:"Чем быстрее сообщите, тем выше шанс вернуть деньги", id:"Semakin cepat melapor, semakin tinggi peluang mendapatkan uang kembali" },
  report_not_fault: { ko:"범죄 피해는 당신의 잘못이 아닙니다.", en:"Being a victim is not your fault.", ja:"犯罪被害はあなたのせいではありません。", zh:"成为受害者不是你的错。", vi:"Trở thành nạn nhân không phải lỗi của bạn.", es:"Ser víctima no es tu culpa.", de:"Opfer zu sein ist nicht Ihre Schuld.", fr:"Être victime n'est pas de votre faute.", hi:"पीड़ित होना आपकी गलती नहीं है।", pt:"Ser vítima não é sua culpa.", th:"การเป็นเหยื่อไม่ใช่ความผิดของคุณ", uz:"Jabrlanuvchi bo'lish sizning aybingiz emas", tl:"Hindi ito kasalanan mo na maging biktima", mn:"Хохирогч болсон нь таны буруу биш", ru:"Стать жертвой — не ваша вина", id:"Menjadi korban bukan salah Anda" },
